1	// claim-office.ts
2	
3	type Customer = {
4	  yearsWithMHPCO: number;
5	};
6	
7	type Item = {
8	  type: string;
9	  cursed?: boolean;
10	};
11	
12	type Step = {
13	  op: string;
14	  items?: Item[];
15	};
16	
17	type ScenarioInput = {
18	  customer: Customer;
19	  steps: Step[];
20	};
21	
22	type ScenarioOutput = {
23	  results: unknown[];
24	};
25	
26	const PROCESSING_FEE = 5;
27	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
28	const CURSE_SURCHARGE_RATE = 0.5;
29	const COMPONENT_BLOCK_SIZE = 3;
30	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
31	
32	const BASE_PREMIUMS: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: 25,
38	  moonstone: 25,
39	};
40	
41	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
42	
43	const isComponentBlock = (type: string, count: number): boolean =>
44	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
45	
46	const curseSurchargeFor = (items: Item[]): number =>
47	  items.reduce(
48	    (surcharge, item) =>
49	      item.cursed
50	        ? surcharge + BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE
51	        : surcharge,
52	    0
53	  );
54	
55	const basePremiumFor = (items: Item[]): number => {
56	  const countsByType = new Map<string, number>();
57	  for (const item of items) {
58	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
59	  }
60	
61	  let basePremium = curseSurchargeFor(items);
62	  for (const [type, count] of countsByType) {
63	    basePremium += isComponentBlock(type, count)
64	      ? COMPONENT_BLOCK_BASE_PREMIUM
65	      : count * BASE_PREMIUMS[type];
66	  }
67	  return basePremium;
68	};
69	
70	const quotePremium = (items: Item[]): number => {
71	  const basePremium = basePremiumFor(items);
72	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
73	  return Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
74	};
75	
76	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
77	  const items = input.steps[0].items ?? [];
78	  return { results: [{ premium: quotePremium(items) }] };
79	};
